import React, { useState, useEffect, useCallback } from 'react';
import axios from 'axios';
import {
  Users, Plus, Edit2, Trash2, Shield, ShieldCheck, X, Save,
  Eye, EyeOff, UserCheck, UserX, Search, ChevronDown, ChevronUp
} from 'lucide-react';

const Funcionarios = () => {
  const [funcionarios, setFuncionarios] = useState([]);
  const [permissoesDisponiveis, setPermissoesDisponiveis] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [editando, setEditando] = useState(null);
  const [busca, setBusca] = useState('');
  const [showSenha, setShowSenha] = useState(false);
  const [expandedId, setExpandedId] = useState(null);
  const [form, setForm] = useState({
    nome: '', email: '', usuario: '', senha: '',
    cargo: 'funcionario', permissoes: [],
  });
  const [error, setError] = useState('');

  const loadFuncionarios = useCallback(async () => {
    try {
      const [funcRes, permRes] = await Promise.all([
        axios.get('/api/admin/funcionarios'),
        axios.get('/api/admin/permissoes-disponiveis'),
      ]);
      setFuncionarios(funcRes.data || []);
      setPermissoesDisponiveis(permRes.data || []);
    } catch (e) {
      console.error('Erro ao carregar funcionários:', e);
    } finally { setLoading(false); }
  }, []);

  useEffect(() => { loadFuncionarios(); }, [loadFuncionarios]);

  const resetForm = () => {
    setForm({ nome: '', email: '', usuario: '', senha: '', cargo: 'funcionario', permissoes: [] });
    setEditando(null);
    setShowForm(false);
    setError('');
    setShowSenha(false);
  };

  const handleEdit = (func) => {
    setForm({
      nome: func.nome,
      email: func.email || '',
      usuario: func.usuario,
      senha: '',
      cargo: func.cargo,
      permissoes: [...(func.permissoes || [])],
    });
    setEditando(func.id);
    setShowForm(true);
    setError('');
  };

  const togglePermissao = (permId) => {
    setForm(prev => ({
      ...prev,
      permissoes: prev.permissoes.includes(permId)
        ? prev.permissoes.filter(p => p !== permId)
        : [...prev.permissoes, permId]
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    try {
      if (editando) {
        const payload = { ...form };
        if (!payload.senha) delete payload.senha;
        await axios.put(`/api/admin/funcionarios/${editando}`, payload);
      } else {
        await axios.post('/api/admin/funcionarios', form);
      }
      resetForm();
      loadFuncionarios();
    } catch (err) {
      setError(err.response?.data?.detail || 'Erro ao salvar');
    }
  };

  const handleDelete = async (func) => {
    if (!window.confirm(`Tem certeza que deseja excluir "${func.nome}"?`)) return;
    try {
      await axios.delete(`/api/admin/funcionarios/${func.id}`);
      loadFuncionarios();
    } catch (err) {
      alert(err.response?.data?.detail || 'Erro ao excluir');
    }
  };

  const handleToggleAtivo = async (func) => {
    try {
      await axios.put(`/api/admin/funcionarios/${func.id}`, { ativo: !func.ativo });
      loadFuncionarios();
    } catch (err) {
      alert(err.response?.data?.detail || 'Erro ao atualizar');
    }
  };

  const filtrados = funcionarios.filter(f =>
    !busca ||
    (f.nome || '').toLowerCase().includes(busca.toLowerCase()) ||
    (f.usuario || '').toLowerCase().includes(busca.toLowerCase()) ||
    (f.email || '').toLowerCase().includes(busca.toLowerCase())
  );

  if (loading) return <div className="flex justify-center py-12"><div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600" /></div>;

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-gray-900 flex items-center gap-2">
            <Users className="h-7 w-7 text-blue-600" /> Funcionários
          </h1>
          <p className="text-sm text-gray-500 mt-1">Gerencie acessos ao painel administrativo</p>
        </div>
        <button onClick={() => { resetForm(); setShowForm(true); }}
          className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 text-sm font-medium">
          <Plus className="h-4 w-4" /> Novo Funcionário
        </button>
      </div>

      {/* Form Modal */}
      {showForm && (
        <div className="fixed inset-0 bg-black bg-opacity-50 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-xl shadow-xl max-w-2xl w-full p-6 max-h-[90vh] overflow-y-auto">
            <div className="flex items-center justify-between mb-4">
              <h3 className="text-lg font-bold text-gray-900">
                {editando ? 'Editar Funcionário' : 'Novo Funcionário'}
              </h3>
              <button onClick={resetForm}><X className="h-5 w-5 text-gray-400" /></button>
            </div>

            {error && <div className="bg-red-50 border border-red-200 text-red-700 px-4 py-2 rounded-lg text-sm mb-4">{error}</div>}

            <form onSubmit={handleSubmit} className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Nome completo *</label>
                  <input type="text" value={form.nome} onChange={e => setForm({ ...form, nome: e.target.value })} required
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500" />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">E-mail</label>
                  <input type="email" value={form.email} onChange={e => setForm({ ...form, email: e.target.value })}
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500" />
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Usuário (login) *</label>
                  <input type="text" value={form.usuario} onChange={e => setForm({ ...form, usuario: e.target.value })} required minLength={3}
                    disabled={!!editando}
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 disabled:bg-gray-100" />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Senha {editando ? '(deixe vazio para manter)' : '*'}
                  </label>
                  <div className="relative">
                    <input type={showSenha ? 'text' : 'password'} value={form.senha}
                      onChange={e => setForm({ ...form, senha: e.target.value })}
                      required={!editando} minLength={4}
                      className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 pr-10" />
                    <button type="button" onClick={() => setShowSenha(!showSenha)}
                      className="absolute right-2 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600">
                      {showSenha ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
                    </button>
                  </div>
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">Cargo *</label>
                <div className="flex gap-3">
                  <button type="button" onClick={() => setForm({ ...form, cargo: 'funcionario' })}
                    className={`flex-1 flex items-center gap-2 px-4 py-3 rounded-lg border-2 text-sm font-medium transition-colors ${form.cargo === 'funcionario' ? 'border-blue-500 bg-blue-50 text-blue-700' : 'border-gray-200 text-gray-600 hover:border-gray-300'}`}>
                    <Shield className="h-5 w-5" />
                    <div className="text-left">
                      <p className="font-semibold">Funcionário</p>
                      <p className="text-xs opacity-70">Acesso limitado, precisa de aprovação</p>
                    </div>
                  </button>
                  <button type="button" onClick={() => setForm({ ...form, cargo: 'gerente' })}
                    className={`flex-1 flex items-center gap-2 px-4 py-3 rounded-lg border-2 text-sm font-medium transition-colors ${form.cargo === 'gerente' ? 'border-purple-500 bg-purple-50 text-purple-700' : 'border-gray-200 text-gray-600 hover:border-gray-300'}`}>
                    <ShieldCheck className="h-5 w-5" />
                    <div className="text-left">
                      <p className="font-semibold">Gerente</p>
                      <p className="text-xs opacity-70">Pode aprovar solicitações</p>
                    </div>
                  </button>
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">Permissões de acesso</label>
                <div className="grid grid-cols-2 gap-2">
                  {permissoesDisponiveis.map(p => (
                    <button key={p.id} type="button" onClick={() => togglePermissao(p.id)}
                      className={`flex items-center gap-2 px-3 py-2 rounded-lg border text-sm transition-colors ${form.permissoes.includes(p.id) ? 'border-green-500 bg-green-50 text-green-700' : 'border-gray-200 text-gray-600 hover:border-gray-300'}`}>
                      <div className={`w-4 h-4 rounded border-2 flex items-center justify-center ${form.permissoes.includes(p.id) ? 'border-green-500 bg-green-500' : 'border-gray-300'}`}>
                        {form.permissoes.includes(p.id) && <svg className="w-3 h-3 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><polyline points="20 6 9 17 4 12" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" /></svg>}
                      </div>
                      {p.nome}
                    </button>
                  ))}
                </div>
                <div className="mt-2 flex gap-2">
                  <button type="button" onClick={() => setForm({ ...form, permissoes: permissoesDisponiveis.map(p => p.id) })}
                    className="text-xs text-blue-600 hover:underline">Marcar todas</button>
                  <button type="button" onClick={() => setForm({ ...form, permissoes: [] })}
                    className="text-xs text-gray-500 hover:underline">Desmarcar todas</button>
                </div>
              </div>

              <div className="flex gap-3 pt-2">
                <button type="button" onClick={resetForm} className="flex-1 px-4 py-2 border border-gray-300 rounded-lg text-sm font-medium text-gray-700 hover:bg-gray-50">Cancelar</button>
                <button type="submit" className="flex-1 flex items-center justify-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-lg text-sm font-medium hover:bg-blue-700">
                  <Save className="h-4 w-4" /> {editando ? 'Salvar Alterações' : 'Criar Funcionário'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Search */}
      <div className="relative">
        <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-gray-400" />
        <input type="text" placeholder="Buscar por nome, usuário ou e-mail..." value={busca} onChange={e => setBusca(e.target.value)}
          className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg text-sm" />
      </div>

      {/* List */}
      {filtrados.length === 0 ? (
        <div className="text-center py-12">
          <Users className="h-12 w-12 text-gray-300 mx-auto mb-3" />
          <p className="text-gray-500">Nenhum funcionário cadastrado</p>
          <p className="text-gray-400 text-sm mt-1">Crie o primeiro funcionário para começar</p>
        </div>
      ) : (
        <div className="space-y-3">
          {filtrados.map(func => (
            <div key={func.id} className={`bg-white rounded-lg shadow border ${func.ativo ? 'border-gray-200' : 'border-red-200 bg-red-50/30'}`}>
              <div className="p-4 flex items-center justify-between">
                <div className="flex items-center gap-3 min-w-0">
                  <div className={`w-10 h-10 rounded-full flex items-center justify-center ${func.cargo === 'gerente' ? 'bg-purple-100' : 'bg-blue-100'}`}>
                    {func.cargo === 'gerente'
                      ? <ShieldCheck className="h-5 w-5 text-purple-600" />
                      : <Shield className="h-5 w-5 text-blue-600" />}
                  </div>
                  <div className="min-w-0">
                    <div className="flex items-center gap-2">
                      <p className="text-sm font-semibold text-gray-900 truncate">{func.nome}</p>
                      <span className={`text-[10px] px-1.5 py-0.5 rounded-full font-medium ${func.cargo === 'gerente' ? 'bg-purple-100 text-purple-700' : 'bg-blue-100 text-blue-700'}`}>
                        {func.cargo === 'gerente' ? 'Gerente' : 'Funcionário'}
                      </span>
                      {!func.ativo && <span className="text-[10px] px-1.5 py-0.5 rounded-full bg-red-100 text-red-700 font-medium">Inativo</span>}
                    </div>
                    <p className="text-xs text-gray-500">@{func.usuario} · {func.email || 'Sem e-mail'}</p>
                  </div>
                </div>

                <div className="flex items-center gap-1.5">
                  <button onClick={() => setExpandedId(expandedId === func.id ? null : func.id)}
                    className="p-1.5 rounded hover:bg-gray-100 text-gray-400" title="Detalhes">
                    {expandedId === func.id ? <ChevronUp className="h-4 w-4" /> : <ChevronDown className="h-4 w-4" />}
                  </button>
                  <button onClick={() => handleToggleAtivo(func)}
                    className={`p-1.5 rounded hover:bg-gray-100 ${func.ativo ? 'text-green-600' : 'text-red-500'}`}
                    title={func.ativo ? 'Desativar' : 'Ativar'}>
                    {func.ativo ? <UserCheck className="h-4 w-4" /> : <UserX className="h-4 w-4" />}
                  </button>
                  <button onClick={() => handleEdit(func)} className="p-1.5 rounded hover:bg-gray-100 text-gray-400" title="Editar">
                    <Edit2 className="h-4 w-4" />
                  </button>
                  <button onClick={() => handleDelete(func)} className="p-1.5 rounded hover:bg-red-50 text-red-400" title="Excluir">
                    <Trash2 className="h-4 w-4" />
                  </button>
                </div>
              </div>

              {expandedId === func.id && (
                <div className="px-4 pb-4 pt-1 border-t border-gray-100">
                  <p className="text-xs font-medium text-gray-500 mb-2">Permissões:</p>
                  <div className="flex flex-wrap gap-1.5">
                    {(func.permissoes || []).length === 0
                      ? <span className="text-xs text-gray-400">Nenhuma permissão atribuída</span>
                      : (func.permissoes || []).map(p => (
                        <span key={p} className="text-xs bg-gray-100 text-gray-700 px-2 py-0.5 rounded-full">{p}</span>
                      ))
                    }
                  </div>
                  <p className="text-xs text-gray-400 mt-2">
                    Criado em {func.criado_em ? new Date(func.criado_em).toLocaleDateString('pt-BR') : '—'} por {func.criado_por || 'admin'}
                  </p>
                </div>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default Funcionarios;
